import tw from 'twin.macro'
import * as React from 'react'
import { Link } from 'gatsby'
import { ReactComponent as LogoIcon } from '../images/logo.svg'
import { isBrowser } from '../util'

interface HeaderProps {}

const links = [
  { to: '/', label: 'Patterns', emphasize: true },
  { to: '/about', label: 'About' },
]

const Header: React.FC<HeaderProps> = () => {
  const [scrolled, setScrolled] = React.useState(false)
  const onScroll = () => isBrowser && setScrolled(window.scrollY > 20)

  React.useEffect(() => {
    if (isBrowser) {
      window.addEventListener('scroll', onScroll)

      setScrolled(window.scrollY > 20)

      return () => window.removeEventListener('scroll', onScroll)
    }
  }, [])

  return (
    <header
      css={[
        tw`w-full fixed z-30 top-0 bg-white transition-all duration-200 ease-in-out`,
        scrolled ? tw`h-12 shadow-lg` : tw`h-20`,
      ]}
      style={{ willChange: 'auto' }}
    >
      <div tw="mx-auto max-w-5xl h-full px-6 flex items-center justify-between">
        <Link to="/">
          <LogoIcon tw="w-3/4 h-3/4 md:w-auto md:h-auto" />
        </Link>
        <div tw="flex gap-3 items-center mr-0 text-sm md:text-base md:gap-10 md:mr-10">
          {links.map(({ to, label, emphasize }) => (
            <Link
              key={to}
              to={to}
              css={[
                tw`text-gray-600 font-semibold transition-colors duration-200 visited:text-gray-600 hover:text-gray-900 hover:no-underline`,
                emphasize &&
                  tw`px-3 py-1 bg-gray-100 hover:bg-gray-200 rounded-lg`,
              ]}
            >
              {label}
            </Link>
          ))}
        </div>
      </div>
    </header>
  )
}

export default Header
